1	import { useCallback, useMemo, useState, useRef } from "react";
2	import {
3		ArrowRight,
4		Check,
5		CheckCircle2,
6		ChevronDown,
7		ChevronLeft,
8		ChevronRight,
9		ChevronUp,
10		HelpCircle,
11		MessageSquare,
12	} from "lucide-react";
13	
14	/** A single blank within a fill-in-the-blank question. */
15	export interface BlankField {
16		/** Placeholder text for the blank input */
17		placeholder?: string;
18		/** Hint shown next to the blank */
19		hint?: string;
20	}
21	
22	/** A single question within an ask_user_question form. */
23	export interface QuestionField {
24		/** Short chip/label shown above the question (e.g. "Goal", "Approach"). */
25		header?: string;
26		/** The question text. For blanks type, use ___ as placeholders. */
27		question: string;
28		/** Question type. Defaults to choice/text hybrid. */
29		type?: "choice" | "text" | "blanks";
30		choices?: string[];
31		/** Allow selecting more than one choice. */
32		multiSelect?: boolean;
33		/** Show a free-text input in addition to (or instead of) choices. */
34		allowText?: boolean;
35		/** Blanks definition for fill-in-the-blank questions. */
36		blanks?: BlankField[];
37		hint?: string;
38	}
39	
40	/** Normalized multi-field form payload. */
41	export interface QuestionFormData {
42		intro?: string;
43		questions: QuestionField[];
44	}
45	
46	/** Legacy single-question payload (kept for backward compatibility). */
47	export interface QuestionData {
48		question: string;
49		choices?: string[];
50		allow_text?: boolean;
51		hint?: string;
52	}
53	
54	export interface AnsweredQuestion {
55		header?: string;
56		question: string;
57		answer: string;
58	}
59	
60	interface QuestionRendererProps {
61		data: QuestionFormData;
62		onSubmit?: (answers: AnsweredQuestion[]) => void;
63	}
64	
65	/**
66	 * Accepts either the new multi-field shape `{ questions: [...] }` or the legacy
67	 * single-question shape `{ question, choices, allow_text, hint }` and returns a
68	 * normalized QuestionFormData. Returns null when nothing renderable is present.
69	 */
70	export function normalizeQuestionForm(raw: unknown): QuestionFormData | null {
71		if (!raw || typeof raw !== "object") return null;
72		const obj = raw as Record<string, unknown>;
73	
74		const coerceField = (value: unknown): QuestionField | null => {
75			if (!value || typeof value !== "object") return null;
76			const q = value as Record<string, unknown>;
77			const question = typeof q.question === "string" ? q.question : "";
78			if (!question) return null;
79			const choices = Array.isArray(q.choices)
80				? q.choices.filter((c): c is string => typeof c === "string")
81				: undefined;
82			const multiSelect =
83				typeof q.multiSelect === "boolean"
84					? q.multiSelect
85					: typeof q.multi_select === "boolean"
86						? q.multi_select
87						: false;
88			const allowText =
89				typeof q.allowText === "boolean"
90					? q.allowText
91					: typeof q.allow_text === "boolean"
92						? q.allow_text
93						: !choices || choices.length === 0;
94			// Detect blanks type
95			const blanks = Array.isArray(q.blanks)
96				? q.blanks.filter((b): b is BlankField => b !== null && typeof b === "object")
97				: undefined;
98			const type: QuestionField["type"] = blanks && blanks.length > 0
99				? "blanks"
100				: typeof q.type === "string" && ["choice", "text", "blanks"].includes(q.type)
101					? (q.type as QuestionField["type"])
102						: undefined;
103			return {
104				header: typeof q.header === "string" ? q.header : undefined,
105				question,
106				type,
107				choices: choices && choices.length > 0 ? choices : undefined,
108				multiSelect,
109				allowText,
110				blanks,
111				hint: typeof q.hint === "string" ? q.hint : undefined,
112			};
113		};
114	
115		if (Array.isArray(obj.questions)) {
116			const questions = obj.questions
117				.map(coerceField)
118				.filter((q): q is QuestionField => q !== null);
119			if (questions.length === 0) return null;
120			return {
121				intro: typeof obj.intro === "string" ? obj.intro : undefined,
122				questions,
123			};
124		}
125	
126		const single = coerceField(obj);
127		if (!single) return null;
128		return { intro: typeof obj.intro === "string" ? obj.intro : undefined, questions: [single] };
129	}
130	
131	interface BlankState {
132		values: string[];
133		selected: string[];
134		text: string;
135	}
136	
137	export function QuestionRenderer({ data, onSubmit }: QuestionRendererProps) {
138		const questions = data.questions;
139		const total = questions.length;
140		const blankRefs = useRef<(HTMLInputElement | null)[]>([]);
141	
142		const countBlanks = (template: string): number => {
143			const matches = template.match(/_{3,}|\{\{blank\}\}/g);
144			return matches ? matches.length : 0;
145		};
146	
147		const [states, setStates] = useState<BlankState[]>(() =>
148			questions.map((q) => {
149				const blankCount = q.blanks?.length ?? countBlanks(q.question);
150				return { values: Array(blankCount).fill(""), selected: [], text: "" };
151			}),
152		);
153		const [submitted, setSubmitted] = useState(false);
154		const [current, setCurrent] = useState(0);
155		const [collapsed, setCollapsed] = useState(false);
156	
157		const answerFor = useCallback(
158			(index: number): string => {
159				const state = states[index];
160				if (!state) return "";
161				const q = questions[index];
162				if (q.type === "blanks" || (q.blanks && q.blanks.length > 0)) {
163					return state.values.filter(Boolean).join(" | ");
164				}
165				const parts = [...state.selected];
166				const text = state.text.trim();
167				if (text) parts.push(text);
168				return parts.join(", ");
169			},
170			[states, questions],
171		);
172	
173		const allAnswered = useMemo(
174			() => questions.every((q, index) => {
175				const state = states[index];
176				if (!state) return false;
177				if (q.type === "blanks" || (q.blanks && q.blanks.length > 0)) {
178					return state.values.every((v) => v.trim().length > 0);
179				}
180				return answerFor(index).length > 0;
181			}),
182			[questions, states, answerFor],
183		);
184	
185		const currentAnswered = useMemo(
186			() => {
187				const q = questions[current];
188				if (!q) return false;
189				const state = states[current];
190				if (!state) return false;
191				if (q.type === "blanks" || (q.blanks && q.blanks.length > 0)) {
192					return state.values.every((v) => v.trim().length > 0);
193				}
194				return answerFor(current).length > 0;
195			},
196			[questions, states, current, answerFor],
197		);
198	
199		const toggleChoice = (index: number, choice: string, multiSelect: boolean) => {
200			if (submitted) return;
201			setStates((current) =>
202				current.map((state, i) => {
203					if (i !== index) return state;
204					if (multiSelect) {
205						const selected = state.selected.includes(choice)
206							? state.selected.filter((c) => c !== choice)
207							: [...state.selected, choice];
208						return { ...state, selected };
209					}
210					return { ...state, selected: state.selected[0] === choice ? [] : [choice] };
211				}),
212			);
213		};
214	
215		const setText = (index: number, value: string) => {
216			if (submitted) return;
217			setStates((current) =>
218				current.map((state, i) => (i === index ? { ...state, text: value } : state)),
219			);
220		};
221	
222		const setBlankValue = (index: number, blankIdx: number, value: string) => {
223			if (submitted) return;
224			setStates((current) =>
225				current.map((state, i) => {
226					if (i !== index) return state;
227					const values = [...state.values];
228					values[blankIdx] = value;
229					return { ...state, values };
230				}),
231			);
232		};
233	
234		/** Split a template into text parts and blank positions */
235		const parseTemplate = (template: string): { text: string; isBlank: boolean; index: number }[] => {
236			const parts: { text: string; isBlank: boolean; index: number }[] = [];
237			const regex = /_{3,}|\{\{blank\}\}/g;
238			let lastIndex = 0;
239			let blankIndex = 0;
240			let match: RegExpExecArray | null;
241	
242			while ((match = regex.exec(template)) !== null) {
243				if (match.index > lastIndex) {
244					parts.push({ text: template.slice(lastIndex, match.index), isBlank: false, index: -1 });
245				}
246				parts.push({ text: match[0], isBlank: true, index: blankIndex++ });
247				lastIndex = match.index + match[0].length;
248			}
249			if (lastIndex < template.length) {
250				parts.push({ text: template.slice(lastIndex), isBlank: false, index: -1 });
251			}
252			return parts;
253		};
254	
255		const handleSubmit = useCallback(() => {
256			if (submitted || !allAnswered) return;
257			const answers: AnsweredQuestion[] = questions.map((q, index) => ({
258				header: q.header,
259				question: q.question,
260				answer: answerFor(index),
261			}));
262			setSubmitted(true);
263			onSubmit?.(answers);
264		}, [submitted, allAnswered, questions, answerFor, onSubmit]);
265	
266		const goNext = useCallback(() => {
267			if (current < total - 1) setCurrent((c) => c + 1);
268		}, [current, total]);
269	
270		const goPrev = useCallback(() => {
271			if (current > 0) setCurrent((c) => c - 1);
272		}, [current]);
273	
274		if (submitted) {
275			return (
276				<div className="my-2 sm:my-3 rounded-lg sm:rounded-xl border border-primary/30 bg-primary/5 p-2.5 sm:p-4 shadow-sm w-full max-w-full overflow-x-hidden">
277					<div className="flex items-start gap-2 sm:gap-3">
278						<div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-primary/10">
279							<CheckCircle2 size={18} className="text-primary" />
280						</div>
281						<div className="min-w-0 flex-1 space-y-2">
282							<p className="text-sm font-medium text-primary">Submitted</p>
283							<div className="space-y-1 text-sm text-primary">
284								{questions.map((q, index) => (
285									<div key={index} className="flex items-start gap-2">
286										<MessageSquare size={14} className="mt-1 shrink-0" />
287										<span className="min-w-0 break-words">
288											{q.header ? `${q.header}: ` : ""}
289											<strong>{answerFor(index)}</strong>
290										</span>
291									</div>
292								))}
293							</div>
294						</div>
295					</div>
296				</div>
297			);
298		}
299	
300		const q = questions[current];
301		if (!q) return null;
302		const state = states[current] ?? { values: [], selected: [], text: "" };
303		const isLast = current === total - 1;
304		const progress = total > 1 ? ((current + 1) / total) * 100 : 100;
305		const isBlanks = q.type === "blanks" || (q.blanks && q.blanks.length > 0);
306	
307		return (
308				<div className="my-2 sm:my-3 rounded-lg sm:rounded-xl border border-primary/30 bg-primary/5 p-2.5 sm:p-4 shadow-sm w-full max-w-full overflow-x-hidden">
309					<div className="flex items-start gap-2 sm:gap-3">
310						<div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-primary/10">
311							<CheckCircle2 size={18} className="text-primary" />
312						</div>
313					<div className="min-w-0 flex-1 space-y-3 sm:space-y-4">
314						<div className="flex items-start justify-between gap-3">
315							<div className="min-w-0">
316								<p className="text-sm font-medium text-primary">Question</p>
317								{collapsed && (
318									<p className="line-clamp-2 text-xs leading-5 text-muted-foreground break-words">
319										{data.intro || q.question}
320									</p>
321								)}
322							</div>
323							<button
324								type="button"
325								onClick={() => setCollapsed((value) => !value)}
326								aria-expanded={!collapsed}
327								className="inline-flex h-8 shrink-0 items-center gap-1 rounded-md border border-border bg-background px-2 text-xs font-medium text-muted-foreground transition-colors hover:border-primary/60 hover:bg-primary/10 hover:text-primary"
328							>
329								{collapsed ? <ChevronDown size={14} /> : <ChevronUp size={14} />}
330								{collapsed ? "Show" : "Hide"}
331							</button>
332						</div>
333						{collapsed ? (
334							<div className="flex items-center gap-2 rounded-lg border border-border/60 bg-background/40 p-3">
335								<div className="h-1.5 flex-1 overflow-hidden rounded-full bg-muted">
336									<div
337										className="h-full rounded-full bg-primary transition-all"
338										style={{ width: `${progress}%` }}
339									/>
340								</div>
341								<span className="font-terminal text-[11px] text-muted-foreground tabular-nums">
342									{current + 1}/{total}
343								</span>
344							</div>
345						) : (
346							<>
347						{data.intro && (
348							<p className="text-sm leading-6 text-muted-foreground break-words">{data.intro}</p>
349						)}
350	
351						{/* Progress bar */}
352						<div className="flex items-center gap-2">
353							<div className="h-1.5 flex-1 overflow-hidden rounded-full bg-muted">
354								<div
355									className="h-full rounded-full bg-primary transition-all"
356									style={{ width: `${progress}%` }}
357								/>
358							</div>
359							<span className="font-terminal text-[11px] text-muted-foreground tabular-nums">
360								{current + 1}/{total}
361							</span>
362						</div>
363	
364						{/* Current question card */}
365						<div className="space-y-3 rounded-lg border border-border/60 bg-background/40 p-2.5 sm:p-3 max-w-full">
366							{q.header && (
367								<span className="inline-flex rounded bg-primary/10 px-2 py-0.5 text-[11px] font-semibold uppercase tracking-wide text-primary">
368									{q.header}
369								</span>
370							)}
371	
372							{/* Fill-in-the-blank rendering */}
373							{isBlanks ? (
374								<div className="space-y-3 max-w-full">
375									<div className="text-sm font-medium leading-relaxed break-words">
376										{parseTemplate(q.question).map((part, idx) => {
377											if (!part.isBlank) {
378												return <span key={idx} className="break-words">{part.text}</span>;
379											}
380											const blankIdx = part.index;
381											const blankDef = q.blanks?.[blankIdx];
382											return (
383												<span key={idx} className="inline-flex items-center gap-1 mx-0.5 sm:mx-1">
384													<input
385														ref={(el) => { blankRefs.current[blankIdx] = el; }}
386														type="text"
387														disabled={submitted}
388														className="inline-block w-16 sm:w-20 h-7 rounded border border-border bg-background px-1.5 sm:px-2 text-sm text-center outline-none focus:border-primary placeholder:text-muted-foreground/50"
389														placeholder={blankDef?.placeholder ?? "___"}
390														value={state.values[blankIdx] ?? ""}
391														onChange={(e) => setBlankValue(current, blankIdx, e.target.value)}
392														onKeyDown={(e) => {
393															if (e.key === "Enter") {
394																const nextBlank = blankRefs.current[blankIdx + 1];
395																if (nextBlank) nextBlank.focus();
396																else if (currentAnswered) {
397																	if (!isLast) goNext();
398																	else if (allAnswered) handleSubmit();
399																}
400															}
401														}}
402													/>
403													{blankDef?.hint && (
404														<span className="text-[10px] text-muted-foreground hidden sm:inline">{blankDef.hint}</span>
405													)}
406												</span>
407											);
408										})}
409									</div>
410								</div>
411							) : (
412								<>
413									<p className="text-sm font-medium leading-6 break-words">{q.question}</p>
414	
415									{q.choices && q.choices.length > 0 && (
416										<div className="space-y-2">
417											{q.choices.map((choice) => {
418												const isSelected = state.selected.includes(choice);
419												return (
420													<button
421														key={choice}
422														type="button"
423														disabled={submitted}
424														aria-pressed={isSelected}
425														className={`flex w-full items-center gap-2.5 sm:gap-3 rounded-lg border-2 px-2.5 py-2 sm:px-4 sm:py-3 text-left text-sm transition-all ${
426															isSelected
427																? "border-primary bg-primary/10 text-primary"
428																: "border-border bg-background hover:border-primary/50"
429														} ${submitted ? "cursor-not-allowed opacity-70" : "cursor-pointer"}`}
430														onClick={() => toggleChoice(current, choice, q.multiSelect ?? false)}
431													>
432														{q.multiSelect ? (
433															<span
434																className={`flex h-4 w-4 shrink-0 items-center justify-center rounded border-2 ${
435																	isSelected ? "border-primary bg-primary text-primary-foreground" : "border-border"
436																}`}
437															>
438																{isSelected ? <Check size={12} /> : null}
439															</span>
440														) : isSelected ? (
441															<CheckCircle2 size={16} className="shrink-0" />
442														) : (
443															<div className="h-4 w-4 shrink-0 rounded-full border-2 border-border" />
444														)}
445														<span className="flex-1 min-w-0 break-words">{choice}</span>
446													</button>
447												);
448											})}
449										</div>
450									)}
451	
452									{q.allowText && (
453										<div className="space-y-2">
454											{q.choices && q.choices.length > 0 && (
455												<div className="flex items-center gap-2 text-xs text-muted-foreground">
456													<div className="h-px flex-1 bg-border" />
457													<span>or type your own</span>
458													<div className="h-px flex-1 bg-border" />
459												</div>
460											)}
461											<input
462												type="text"
463												className="h-9 w-full rounded-md border border-border bg-background px-3 text-sm outline-none focus:border-primary"
464												placeholder="Your answer..."
465												value={state.text}
466												disabled={submitted}
467												onChange={(e) => setText(current, e.target.value)}
468												onKeyDown={(e) => {
469													if (e.key === "Enter" && currentAnswered) {
470														if (!isLast) goNext();
471														else if (allAnswered) handleSubmit();
472													}
473												}}
474											/>
475										</div>
476									)}
477								</>
478							)}
479	
480							{q.hint && !submitted && (
481								<p className="text-xs italic text-muted-foreground break-words">💡 {q.hint}</p>
482							)}
483						</div>
484	
485						{/* Navigation */}
486						<div className="flex items-center justify-between gap-2">
487							<button
488								type="button"
489								onClick={goPrev}
490								disabled={current === 0}
491								className="inline-flex items-center gap-1 rounded-lg border-2 border-border bg-background px-2.5 sm:px-3 py-2 text-sm font-medium hover:bg-accent disabled:opacity-40 disabled:pointer-events-none transition-colors"
492							>
493								<ChevronLeft size={14} />
494								Back
495							</button>
496	
497							{!isLast ? (
498								<button
499									type="button"
500									onClick={goNext}
501									className="inline-flex items-center gap-1 rounded-lg border-2 border-primary bg-primary px-3 sm:px-4 py-2 text-sm font-medium text-primary-foreground hover:bg-primary/90 transition-colors"
502								>
503									Next
504									<ChevronRight size={14} />
505								</button>
506							) : (
507								<button
508									type="button"
509									disabled={!allAnswered}
510									className="inline-flex items-center gap-2 rounded-lg border-2 border-primary bg-primary px-3 sm:px-4 py-2 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-40 disabled:pointer-events-none transition-colors"
511									onClick={handleSubmit}
512								>
513									<ArrowRight size={16} />
514									{total === 1 ? "Answer" : "Submit answers"}
515								</button>
516							)}
517						</div>
518							</>
519						)}
520					</div>
521				</div>
522			</div>
523		);
524	}
