1	import { type ReactNode, useEffect, useMemo, useRef, useState } from "react";
2	import { History, Loader2, Plus, Search, X } from "lucide-react";
3	import { keatingStorage, sessions, updateSessionTitle } from "../hooks/keating-storage";
4	import type { SessionMetadata } from "../types/session";
5	import { buildSessionTree, type SessionTreeNode } from "./session-tree";
6	import { SessionCard } from "./SessionCard";
7	import { ForkMapCard } from "./ForkMapCard";
8	import {
9		type ArtifactHero,
10		buildArtifactHeroMap,
11		MASONRY_GAP_PX,
12		MASONRY_ROW_PX,
13		pxToSpan,
14	} from "./session-card-visuals";
15	
16	export interface SessionCardGridProps {
17		activeSessionId?: string;
18		forkingSessionId?: string | null;
19		forkedSessionId?: string | null;
20		onLoad: (sessionId: string) => void | Promise<void>;
21		onFork: (sessionId: string) => void | Promise<void>;
22		onOpenSessions: () => void;
23		onNewSession?: () => void;
24		onClose?: () => void;
25	}
26	
27	function notifySessionsChanged() {
28		window.dispatchEvent(new Event("keating:sessions-changed"));
29	}
30	
31	/**
32	 * Re-measures its child's natural height and spans the right number of 8px grid
33	 * rows so a CSS-grid masonry packs without gaps. Fork-map cards span both columns.
34	 */
35	function MasonryItem({ children, fullWidth }: { children: ReactNode; fullWidth?: boolean }) {
36		const ref = useRef<HTMLDivElement>(null);
37		const [span, setSpan] = useState(20);
38	
39		useEffect(() => {
40			const el = ref.current;
41			if (!el) return;
42			const measure = () => setSpan(pxToSpan(el.getBoundingClientRect().height));
43			measure();
44			const observer = new ResizeObserver(measure);
45			observer.observe(el);
46			return () => observer.disconnect();
47		}, []);
48	
49		return (
50			<div className="min-w-0" style={{ gridRow: `span ${span}`, gridColumn: fullWidth ? "1 / -1" : undefined }}>
51				<div ref={ref} className="min-w-0">{children}</div>
52			</div>
53		);
54	}
55	
56	export function SessionCardGrid({
57		activeSessionId,
58		forkingSessionId,
59		forkedSessionId,
60		onLoad,
61		onFork,
62		onOpenSessions,
63		onNewSession,
64		onClose,
65	}: SessionCardGridProps) {
66		const [items, setItems] = useState<SessionMetadata[]>([]);
67		const [heroes, setHeroes] = useState<Map<string, ArtifactHero>>(new Map());
68		const [loading, setLoading] = useState(true);
69		const [query, setQuery] = useState("");
70		const [forkedSource, setForkedSource] = useState<string | null>(null);
71	
72		useEffect(() => {
73			let cancelled = false;
74			const reload = async () => {
75				try {
76					const [metadata, heroMap] = await Promise.all([
77						sessions.getAllMetadata() as Promise<SessionMetadata[]>,
78						buildArtifactHeroMap(keatingStorage).catch(() => new Map<string, ArtifactHero>()),
79					]);
80					if (cancelled) return;
81					setItems(metadata);
82					setHeroes(heroMap);
83				} finally {
84					if (!cancelled) setLoading(false);
85				}
86			};
87			void reload();
88			const onChanged = () => void reload();
89			window.addEventListener("keating:sessions-changed", onChanged);
90			return () => {
91				cancelled = true;
92				window.removeEventListener("keating:sessions-changed", onChanged);
93			};
94		}, []);
95	
96		const normalizedQuery = query.trim().toLowerCase();
97	
98		const flatCards = useMemo(() => {
99			if (!normalizedQuery) return null;
100			return items
101				.filter((session) =>
102					[session.title, session.preview, new Date(session.lastModified).toLocaleString()]
103						.some((value) => value.toLowerCase().includes(normalizedQuery)),
104				)
105				.sort((left, right) => right.lastModified.localeCompare(left.lastModified))
106				.slice(0, 60);
107		}, [items, normalizedQuery]);
108	
109		const roots: SessionTreeNode[] = useMemo(
110			() => (normalizedQuery ? [] : buildSessionTree(items)),
111			[items, normalizedQuery],
112		);
113	
114		const handleRename = async (id: string, title: string) => {
115			await updateSessionTitle(id, title);
116		};
117		const handleDelete = async (id: string) => {
118			await sessions.deleteSession(id);
119			notifySessionsChanged();
120		};
121		const handleFork = async (id: string) => {
122			await onFork(id);
123			setForkedSource(id);
124			window.setTimeout(() => setForkedSource((current) => (current === id ? null : current)), 1800);
125		};
126	
127		const isEmpty = !loading && (normalizedQuery ? flatCards?.length === 0 : roots.length === 0);
128	
129		return (
130			<>
131				<div className="fixed inset-0 z-40 bg-black/40" onClick={onClose} aria-hidden="true" />
132				{/* Intentionally not role="dialog": a global mobile rule
133				    (`[role=dialog] button { width: 100% }`) would stretch every card
134				    and chrome button. The overlay is labelled for assistive tech instead. */}
135				<aside
136					className="session-card-grid fixed inset-0 z-50 flex flex-col bg-background"
137					aria-label="Sessions"
138				>
139					<header className="flex items-center gap-2 border-b border-border px-4 py-3">
140						<History size={16} className="shrink-0 text-foreground" />
141						<h2 className="flex-1 text-base font-semibold">Sessions</h2>
142						<button
143							type="button"
144							className="inline-flex h-8 items-center rounded-md border border-border px-2.5 text-xs hover:bg-accent"
145							onClick={onOpenSessions}
146						>
147							Manage
148						</button>
149						{onClose ? (
150							<button
151								type="button"
152								className="inline-flex h-8 w-8 items-center justify-center rounded-md border border-border text-muted-foreground hover:bg-accent hover:text-accent-foreground"
153								aria-label="Close sessions"
154								onClick={onClose}
155							>
156								<X size={16} />
157							</button>
158						) : null}
159					</header>
160	
161					<div className="flex items-center gap-2 border-b border-border px-4 py-2.5">
162						{onNewSession ? (
163							<button
164								type="button"
165								className="inline-flex h-9 shrink-0 items-center gap-1.5 rounded-md bg-primary px-3 text-sm font-medium text-primary-foreground hover:bg-primary/90"
166								onClick={() => {
167									onNewSession();
168									onClose?.();
169								}}
170							>
171								<Plus size={16} />
172								New
173							</button>
174						) : null}
175						<label className="flex min-h-9 flex-1 items-center gap-2 rounded-md border border-border bg-background px-3 text-sm">
176							<Search size={15} className="shrink-0 text-muted-foreground" />
177							<input
178								className="min-w-0 flex-1 bg-transparent outline-none placeholder:text-muted-foreground"
179								value={query}
180								placeholder="Search sessions"
181								onChange={(event) => setQuery(event.target.value)}
182							/>
183						</label>
184					</div>
185	
186					<div className="min-h-0 flex-1 overflow-y-auto p-3">
187						{loading ? (
188							<div className="flex items-center justify-center gap-2 py-12 text-sm text-muted-foreground">
189								<Loader2 className="h-4 w-4 animate-spin" />
190								Loading…
191							</div>
192						) : isEmpty ? (
193							<div className="py-12 text-center text-sm text-muted-foreground">
194								{items.length === 0 ? "No sessions yet" : "No sessions match your search"}
195							</div>
196						) : (
197							<div
198								className="grid grid-cols-2 items-start"
199								style={{ gridAutoRows: `${MASONRY_ROW_PX}px`, gap: `${MASONRY_GAP_PX}px` }}
200							>
201								{flatCards
202									? flatCards.map((session) => (
203											<MasonryItem key={session.id}>
204												<SessionCard
205													session={session}
206													hero={heroes.get(session.id)}
207													active={session.id === activeSessionId}
208													forking={session.id === forkingSessionId}
209													justForked={session.id === forkedSource || session.id === forkedSessionId}
210													onLoad={onLoad}
211													onFork={handleFork}
212													onRename={handleRename}
213													onDelete={handleDelete}
214												/>
215											</MasonryItem>
216										))
217									: roots.map((root) =>
218											root.children.length > 0 ? (
219												<MasonryItem key={root.session.id} fullWidth>
220													<ForkMapCard
221														root={root}
222														activeSessionId={activeSessionId}
223														forkingSessionId={forkingSessionId}
224														onLoad={onLoad}
225														onFork={handleFork}
226														onRename={handleRename}
227														onDelete={handleDelete}
228													/>
229												</MasonryItem>
230											) : (
231												<MasonryItem key={root.session.id}>
232													<SessionCard
233														session={root.session}
234														hero={heroes.get(root.session.id)}
235														active={root.session.id === activeSessionId}
236														forking={root.session.id === forkingSessionId}
237														justForked={root.session.id === forkedSource || root.session.id === forkedSessionId}
238														onLoad={onLoad}
239														onFork={handleFork}
240														onRename={handleRename}
241														onDelete={handleDelete}
242													/>
243												</MasonryItem>
244											),
245										)}
246							</div>
247						)}
248					</div>
249				</aside>
250			</>
251		);
252	}
