import { useEffect, useRef, useState } from "react";
import {
	Check,
	Code2,
	Film,
	FlaskConical,
	GitBranch,
	Landmark,
	Languages,
	ListChecks,
	Loader2,
	Map as MapIcon,
	MoreVertical,
	Palette,
	Pencil,
	Sigma,
	Sparkles,
	Trash2,
	X,
} from "lucide-react";
import type { LucideIcon } from "lucide-react";
import type { SessionMetadata } from "../types/session";
import {
	type ArtifactHero,
	type CategoryKey,
	categorize,
	categoryGradient,
} from "./session-card-visuals";

const CATEGORY_ICON: Record<CategoryKey, LucideIcon> = {
	science: FlaskConical,
	"physics-math": Sigma,
	history: Landmark,
	cs: Code2,
	language: Languages,
	arts: Palette,
	general: Sparkles,
};

const HERO_ICON = {
	map: MapIcon,
	animation: Film,
	plan: ListChecks,
} as const;

export interface SessionCardProps {
	session: SessionMetadata;
	hero?: ArtifactHero;
	/** Number of direct forks, shown as a badge when this card stands alone. */
	childCount?: number;
	active?: boolean;
	forking?: boolean;
	justForked?: boolean;
	onLoad: (sessionId: string) => void | Promise<void>;
	onFork: (sessionId: string) => void | Promise<void>;
	onRename: (sessionId: string, title: string) => void | Promise<void>;
	onDelete: (sessionId: string) => void | Promise<void>;
}

function formatDate(isoString: string) {
	const date = new Date(isoString);
	const now = new Date();
	const days = Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60 * 24));
	if (days === 0) {
		return date.toLocaleTimeString([], { hour: "numeric", minute: "2-digit" });
	}
	if (days === 1) return "Yesterday";
	if (days < 7) return `${days}d ago`;
	return date.toLocaleDateString();
}

export function SessionCard({
	session,
	hero,
	childCount = 0,
	active = false,
	forking = false,
	justForked = false,
	onLoad,
	onFork,
	onRename,
	onDelete,
}: SessionCardProps) {
	const category = categorize(session.title);
	const Icon = CATEGORY_ICON[category.key];
	const [menuOpen, setMenuOpen] = useState(false);
	const [renaming, setRenaming] = useState(false);
	const [confirmingDelete, setConfirmingDelete] = useState(false);
	const [draft, setDraft] = useState(session.title);
	const [busy, setBusy] = useState(false);
	const menuRef = useRef<HTMLDivElement>(null);

	useEffect(() => {
		if (!menuOpen) return;
		const onDown = (event: MouseEvent) => {
			if (!menuRef.current?.contains(event.target as Node)) setMenuOpen(false);
		};
		window.addEventListener("mousedown", onDown);
		return () => window.removeEventListener("mousedown", onDown);
	}, [menuOpen]);

	const saveRename = async () => {
		const next = draft.trim();
		if (!next || next === session.title.trim()) {
			setRenaming(false);
			return;
		}
		setBusy(true);
		try {
			await onRename(session.id, next);
			setRenaming(false);
		} finally {
			setBusy(false);
		}
	};

	const confirmDelete = async () => {
		setBusy(true);
		try {
			await onDelete(session.id);
		} finally {
			setBusy(false);
			setConfirmingDelete(false);
		}
	};

	const HeroBadgeIcon = hero ? HERO_ICON[hero.type] : null;

	return (
		<div
			className={`group relative flex h-full flex-col overflow-hidden rounded-2xl border text-left shadow-sm transition-colors ${
				active ? "border-primary ring-1 ring-primary" : "border-border"
			} ${justForked ? "session-fork-arrive" : ""}`}
		>
			{/* Hero band: rendered map SVG when available, otherwise a category tile. */}
			<button
				type="button"
				className="relative block w-full text-left"
				onClick={() => void onLoad(session.id)}
				aria-label={`Open session ${session.title}`}
			>
				{hero?.svg ? (
					<div
						className="session-card-hero-svg flex h-28 w-full items-center justify-center overflow-hidden bg-muted/40"
						// Locally generated mermaid SVG from the user's own IndexedDB.
						dangerouslySetInnerHTML={{ __html: hero.svg }}
					/>
				) : (
					<div
						className="flex h-20 w-full items-center justify-between px-4"
						style={{ background: categoryGradient(category.accent) }}
					>
						<Icon size={26} style={{ color: category.accent }} aria-hidden="true" />
						<span
							className="rounded-full px-2 py-0.5 text-[10px] font-medium uppercase tracking-wide"
							style={{ color: category.accent, background: `${category.accent}1f` }}
						>
							{category.label}
						</span>
					</div>
				)}
				{HeroBadgeIcon ? (
					<span className="absolute left-2 top-2 inline-flex items-center gap-1 rounded-full bg-background/85 px-2 py-0.5 text-[10px] font-medium text-foreground backdrop-blur">
						<HeroBadgeIcon size={11} />
						{hero?.type}
					</span>
				) : null}
			</button>

			<button
				type="button"
				className="flex min-w-0 flex-1 flex-col px-3.5 pb-3 pt-2.5 text-left"
				onClick={() => void onLoad(session.id)}
			>
				<span className="text-[11px] text-muted-foreground">{formatDate(session.lastModified)}</span>
				<h3 className="mt-0.5 flex min-w-0 items-center gap-1.5 text-sm font-semibold leading-snug text-foreground">
					{session.parentSessionId ? (
						<GitBranch size={13} className="mt-0.5 shrink-0 self-start text-primary" />
					) : null}
					<span className="line-clamp-3 break-words">{session.title}</span>
				</h3>
				{session.preview ? (
