	type ArtifactHero,
	type CategoryKey,
	categorize,
	categoryGradient,
} from "./session-card-visuals";

const CATEGORY_ICON: Record<CategoryKey, LucideIcon> = {
	science: FlaskConical,
	"physics-math": Sigma,
	history: Landmark,
	cs: Code2,
	language: Languages,
	arts: Palette,
	general: Sparkles,
};

const HERO_ICON = {
	map: MapIcon,
	animation: Film,
	plan: ListChecks,
