function UserMessage({
  components,
  profileImage,
}: {
  components: ReturnType<typeof messagePartComponents>;
  profileImage?: string | null;
}) {
  return (
    <MessagePrimitive.Root className="mx-auto mb-4 flex w-full max-w-3xl justify-end">
      <div className="flex max-w-[88%] gap-3 rounded-lg border-2 border-green-700 bg-green-500 px-4 py-3 text-sm text-white shadow-sm dark:border-green-400 dark:bg-green-600 sm:max-w-[82%]">
        <div className="mt-0.5 flex h-5 w-5 shrink-0 items-center justify-center overflow-hidden rounded bg-white/15">
          {profileImage ? (
            <img
              src={profileImage}
              alt="You"
              className="h-full w-full object-cover"
            />
          ) : (
            <User className="h-4 w-4 shrink-0" />
          )}
        </div>
        <div className="min-w-0">
          <div className="mb-1 text-[10px] font-semibold uppercase tracking-wide text-white/80">
            Learner
          </div>
          <div className="whitespace-pre-wrap leading-6 font-ui">
            <MessagePrimitive.Content components={components} />
          </div>
        </div>
      </div>
    </MessagePrimitive.Root>
  );
}

function FeedbackModal({
  open,
  type,
  onClose,
  onSubmit,
}: {
  open: boolean;
  type: "up" | "down";
  onClose: () => void;
  onSubmit: (type: "up" | "down", comment: string) => void;
}) {
  const [comment, setComment] = useState("");

  useEffect(() => {
    if (open) setComment("");
  }, [open]);

  if (!open) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm px-4"
      onClick={onClose}
    >
      <div
        className="w-full max-w-md rounded-lg border border-border bg-background p-5 shadow-lg"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex items-center justify-between mb-3">
          <h3 className="text-sm font-semibold text-foreground">
            {type === "up" ? "What was helpful?" : "What could be improved?"}
          </h3>
          <button
            type="button"
            className="inline-flex h-7 w-7 items-center justify-center rounded-md text-muted-foreground hover:bg-accent hover:text-accent-foreground"
            onClick={onClose}
            aria-label="Close"
          >
            <X size={14} />
          </button>
        </div>
        <textarea
          className="w-full rounded-md border border-border bg-muted/30 px-3 py-2 text-sm text-foreground outline-none placeholder:text-muted-foreground resize-none"
          rows={4}
          placeholder="Optional comment..."
          value={comment}
          onChange={(e) => setComment(e.target.value)}
          autoFocus
        />
        <div className="mt-3 flex justify-end gap-2">
          <button
            type="button"
            className="inline-flex h-8 items-center justify-center rounded-md border border-border px-3 text-xs text-muted-foreground hover:bg-accent hover:text-accent-foreground"
            onClick={onClose}
          >
            Skip
